     1→import React, { useMemo, useRef, useState } from "react"
     2→import MyOrdersCashbackView from "./view"
     3→import { NavigationProp, useFocusEffect, useNavigation } from "@react-navigation/native";
     4→import { PropsRootStack } from "src/routes/Models";
     5→import { format, parseISO } from "date-fns";
     6→import { PropsModalizeRef } from "@semparar/design-system-app/src/@types/modelize";
     7→import { eventSelectContent, eventScreenViewV3 } from '~/constants/functions';
     8→import { getPointsExtract } from '../../services/services';
     9→import { useShallow } from "zustand/react/shallow";
    10→import { useRootStore } from '~/store';
    11→import { PointsExtractStatus } from "../../services/models";
    12→import { Dimensions } from "react-native";
    13→import { FilterGroup } from "../ExtractRewardProgram/Models";
    14→
    15→
    16→const MyOrdersCashback = () => {
    17→
    18→    const [isRefreshing, setIsRefreshing] = useState(false);
    19→
    20→    const modalizeRefFilters = useRef<PropsModalizeRef>(null);
    21→    const emptyImage = "https://image.mkt-semparar.com.br/lib/fe2f117170640475721171/m/1/shopping_cart.png"
    22→
    23→    const SKELETON_COUNT = 3;
    24→    const { width } = Dimensions.get('window');
    25→
    26→    const { pointsExtract, pointsExtractActions } =
    27→        useRootStore(
    28→            useShallow((state) => ({
    29→                pointsExtract: state.pointsExtract,
    30→                pointsExtractActions: state.pointsExtractActions
    31→            })),
    32→        );
    33→
    34→    const getFormatDate = (iso?: string) => {
    35→        if (!iso) return '';
    36→        const date = parseISO(iso);
    37→        return format(date, 'dd/MM/yyyy');
    38→    };
    39→
    40→    const getFilterGroups: FilterGroup[] = useMemo(() => {
    41→        return [{
    42→            label: 'Períodos',
    43→            options: [
    44→                { label: '7 dias', value: 0 },
    45→                { label: '15 dias', value: 1 },
    46→                { label: '30 dias', value: 2 },
    47→                { label: '60 dias', value: 3 },
    48→                { label: '90 dias', value: 4 },
    49→            ],
    50→        }, {
    51→            label: 'Tipos de lançamentos',
    52→            options: [
    53→                { label: 'Mais recentes', value: 'ASC' },
    54→                { label: 'Mais antigas', value: 'DESC' },
    55→            ],
    56→        }];
    57→    }, []);
    58→
    59→
    60→    const handleOpenFilters = () => {
    61→        eventSelectContent({
    62→            content_type: 'cta',
    63→            content_id: 'filtro_pedidos',
    64→            location_1: 'monetizacao',
    65→            location_2: 'hub_recompensas_spmais',
    66→            location_3: 'meus_pedidos',
    67→        });
    68→
    69→        modalizeRefFilters.current?.open?.();
    70→    }
    71→
    72→    const handleDetailsOrders = () => {
    73→        eventSelectContent({
    74→            content_type: 'cta',
    75→            content_id: 'detalhe_pedido',
    76→            location_1: 'monetizacao',
    77→            location_2: 'hub_recompensas_spmais',
    78→            location_3: 'meus_pedidos',
    79→        });
    80→    }
    81→
    82→
    83→    const myOrders = pointsExtract?.extractData?.transactions || []
    84→
    85→    const isLoading = pointsExtract.status === PointsExtractStatus.LOADING
    86→    const isError = pointsExtract.status === PointsExtractStatus.ERROR
    87→
    88→    const navigation = useNavigation<NavigationProp<PropsRootStack>>();
    89→
    90→    const handleGoBack = () => {
    91→        pointsExtractActions.clearTransactionsFilters()
    92→        pointsExtractActions.reset()
    93→        navigation.goBack()
    94→    }
    95→
    96→    const handleRefresh = async () => {
    97→        setIsRefreshing(true);
    98→        await getPointsExtract({ type: 'Resgate' });
    99→        setIsRefreshing(false);
   100→    };
   101→
   102→    const hasFocused = useRef(false);
   103→    useFocusEffect(
   104→        React.useCallback(() => {
   105→            if (!hasFocused.current) {
   106→                eventScreenViewV3(
   107→                    'meus_pedidos',
   108→                    'hub_recompensas_spmais',
   109→                    'monetizacao',
   110→                    {
   111→                        location_1: 'monetizacao',
   112→                        location_2: 'hub_recompensas_spmais',
   113→                        location_3: 'meus_pedidos',
   114→                    }
   115→                );
   116→                pointsExtractActions.clearTransactionsFilters()
   117→                pointsExtractActions.reset()
   118→                getPointsExtract({ type: 'Resgate' });
   119→                hasFocused.current = true;
   120→            }
   121→            return () => {
   122→                hasFocused.current = false;
   123→            };
   124→        }, [])
   125→    )
   126→
   127→    return (
   128→        <MyOrdersCashbackView
   129→            myOrders={myOrders}
   130→            emptyImage={emptyImage}
   131→            isLoading={isLoading}
   132→            isError={isError}
   133→            filterGroups={getFilterGroups}
   134→            modalizeRefFilters={modalizeRefFilters}
   135→            formatDate={getFormatDate}
   136→            handleGoBack={handleGoBack}
   137→            handleOpenFilters={handleOpenFilters}
   138→            handleDetailsOrders={handleDetailsOrders}
